#include <pthread.h>
#include <stdio.h>

volatile int flag[2] = {0, 0};
volatile int turn = 0;

void* process0(void* arg) {
 while(1) {
 flag[0] = 1;
 turn = 1;
 while(flag[1] && turn == 1);

 // Critical Section
 printf("Process 0 in CS\n");

 flag[0] = 0;
 // Remainder Section
 }
}

void* process1(void* arg) {
 while(1) {
 flag[1] = 1;
 turn = 0;
 while(flag[0] && turn == 0);

 // Critical Section
 printf("Process 1 in CS\n");

 flag[1] = 0;
 // Remainder Section
 }
}

int main() {
 pthread_t t0, t1;
 pthread_create(&t0, NULL, process0, NULL);
 pthread_create(&t1, NULL, process1, NULL);
 pthread_join(t0, NULL);
 pthread_join(t1, NULL);
 return 0;
}
